import { useState, useEffect } from "react";
import { useParams, useSearchParams, useNavigate } from "react-router-dom";
import { useAuth } from "../hooks/useAuth";
import api from "../utils/api";

const STEPS = ["Цаг сонгох", "Суудал сонгох", "Баталгаажуулах"];

export default function BookingPage() {
  const { id } = useParams();
  const [sp] = useSearchParams();
  const nav = useNavigate();
  const { user } = useAuth();

  const [step, setStep]           = useState(1);
  const [biz, setBiz]             = useState(null);
  const [services, setServices]   = useState([]);
  const [seats, setSeats]         = useState([]);
  const [bookedSeats, setBooked]  = useState([]);
  const [slots, setSlots]         = useState([]);

  const [selService, setService]  = useState(sp.get("serviceId") || "");
  const [selDate, setDate]        = useState(new Date().toISOString().slice(0,10));
  const [selTime, setTime]        = useState("");
  const [selSeat, setSeat]        = useState("");
  const [note, setNote]           = useState("");
  const [loading, setLoading]     = useState(false);
  const [msg, setMsg]             = useState("");

  useEffect(() => {
    api.get(`/businesses/${id}`).then(({ data }) => {
      setBiz(data.data);
      setServices(data.data.services || []);
      setSeats(data.data.seats || []);
    });
  }, [id]);

  // Сул цаг татах
  useEffect(() => {
    if (!selDate || !selService) return;
    api.get(`/bookings/availability?businessId=${id}&date=${selDate}&serviceId=${selService}`)
      .then(({ data }) => setSlots(data.data))
      .catch(() => setSlots([]));
  }, [selDate, selService, id]);

  // Захиалагдсан суудал татах
  useEffect(() => {
    if (!selTime || !selDate) return;
    const dt = `${selDate}T${selTime}:00`;
    api.get(`/bookings/booked-seats?businessId=${id}&datetime=${dt}`)
      .then(({ data }) => setBooked(data.data))
      .catch(() => setBooked([]));
  }, [selTime, selDate, id]);

  const submit = async () => {
    if (!user) { nav("/login"); return; }
    setLoading(true); setMsg("");
    try {
      const datetime = new Date(`${selDate}T${selTime}:00`);
      await api.post("/bookings", {
        businessId: id, serviceId: selService,
        seatId: selSeat || undefined, datetime, note,
      });
      nav("/my-bookings");
    } catch (e) {
      setMsg(e.response?.data?.message || "Алдаа гарлаа");
    }
    setLoading(false);
  };

  const selSvc = services.find(s => s._id === selService);

  // Суудлуудыг row-р бүлэглэх
  const seatsByRow = seats.reduce((acc, s) => {
    if (!acc[s.row]) acc[s.row] = [];
    acc[s.row].push(s);
    return acc;
  }, {});

  return (
    <div style={{ maxWidth:900, margin:"0 auto", padding:"32px 20px" }}>
      {/* Progress */}
      <div style={{ display:"flex", alignItems:"center", gap:0, marginBottom:32, justifyContent:"center" }}>
        {STEPS.map((s, i) => (
          <div key={i} style={{ display:"flex", alignItems:"center" }}>
            <div style={{ display:"flex", flexDirection:"column", alignItems:"center", gap:6 }}>
              <div style={{
                width:36, height:36, borderRadius:"50%",
                display:"flex", alignItems:"center", justifyContent:"center",
                fontWeight:700, fontSize:14,
                background: step > i+1 ? "var(--teal)" : step===i+1 ? "var(--blue)" : "var(--card)",
                color: step >= i+1 ? "#fff" : "var(--muted)",
                border: `2px solid ${step >= i+1 ? (step>i+1?"var(--teal)":"var(--blue)") : "var(--border)"}`,
              }}>{step > i+1 ? "✓" : i+1}</div>
              <span style={{ fontSize:12, color: step===i+1 ? "var(--text)" : "var(--muted)" }}>{s}</span>
            </div>
            {i < STEPS.length-1 && (
              <div style={{ width:80, height:2, margin:"0 4px 18px",
                background: step > i+1 ? "var(--teal)" : "var(--border)" }} />
            )}
          </div>
        ))}
      </div>

      <div style={{ display:"grid", gridTemplateColumns:"1fr 300px", gap:20 }}>
        {/* Left */}
        <div>
          {/* STEP 1 */}
          {step === 1 && (
            <div className="card">
              <h3 style={{ marginBottom:20, fontSize:16 }}>📅 Алхам 1: Өдөр болон цаг</h3>

              {/* Service select */}
              <div style={{ marginBottom:16 }}>
                <label>Үйлчилгээ сонгох</label>
                <select value={selService} onChange={e=>setService(e.target.value)} className="input">
                  <option value="">-- Сонгох --</option>
                  {services.map(s => (
                    <option key={s._id} value={s._id}>
                      {s.name} — ₮{s.price.toLocaleString()} ({s.duration} мин)
                    </option>
                  ))}
                </select>
              </div>

              {/* Date */}
              <div style={{ marginBottom:16 }}>
                <label>Өдөр сонгох</label>
                <input type="date" value={selDate}
                  min={new Date().toISOString().slice(0,10)}
                  onChange={e=>setDate(e.target.value)} className="input" />
              </div>

              {/* Time slots */}
              <div>
                <label>Боломжтой цагууд</label>
                <div style={{ display:"flex", flexWrap:"wrap", gap:8, marginTop:4 }}>
                  {slots.length === 0 && (
                    <div style={{ color:"var(--muted)", fontSize:13 }}>
                      {selService ? "Цаг байхгүй" : "Үйлчилгээ сонгоно уу"}
                    </div>
                  )}
                  {slots.map(sl => (
                    <button key={sl.time} disabled={!sl.available}
                      onClick={() => setTime(sl.time)}
                      style={{
                        padding:"8px 16px", borderRadius:8, fontSize:13, fontWeight:500,
                        cursor: sl.available ? "pointer" : "not-allowed",
                        border:"1px solid",
                        background: selTime===sl.time ? "var(--blue)" :
                          sl.available ? "var(--card)" : "var(--surface)",
                        color: selTime===sl.time ? "#fff" :
                          sl.available ? "var(--text)" : "var(--muted)",
                        borderColor: selTime===sl.time ? "var(--blue)" : "var(--border)",
                        textDecoration: !sl.available ? "line-through" : "none",
                        transition:"all .15s",
                      }}>{sl.time}</button>
                  ))}
                </div>
              </div>

              <button onClick={() => setStep(2)} disabled={!selService || !selTime}
                className="btn btn-primary"
                style={{ marginTop:20, width:"100%", padding:"12px 0",
                  opacity: (!selService || !selTime) ? 0.5 : 1 }}>
                Суудал сонгох →
              </button>
            </div>
          )}

          {/* STEP 2 — 2D Seat map */}
          {step === 2 && (
            <div className="card">
              <h3 style={{ marginBottom:6, fontSize:16 }}>💺 Алхам 2: Суудал сонгох</h3>
              <div style={{ display:"flex", gap:16, marginBottom:20, fontSize:12 }}>
                <span><span style={{ display:"inline-block", width:12, height:12,
                  borderRadius:2, background:"var(--card)", border:"1px solid var(--border)",
                  verticalAlign:"middle", marginRight:4 }} />Сул</span>
                <span><span style={{ display:"inline-block", width:12, height:12,
                  borderRadius:2, background:"var(--blue)", verticalAlign:"middle", marginRight:4 }} />Сонгосон</span>
                <span><span style={{ display:"inline-block", width:12, height:12,
                  borderRadius:2, background:"rgba(239,68,68,0.3)", border:"1px solid var(--red)",
                  verticalAlign:"middle", marginRight:4 }} />Захиалагдсан</span>
              </div>

              {/* Screen indicator */}
              <div style={{
                width:"70%", margin:"0 auto 24px",
                padding:"8px 0", textAlign:"center",
                background:"var(--surface)", borderRadius:6,
                fontSize:12, color:"var(--muted)",
                borderBottom:"3px solid var(--blue)",
              }}>🎬 ДЭЛГЭЦ / ҮЙЛЧИЛГЭЭ</div>

              {/* Seat grid */}
              <div style={{ display:"flex", flexDirection:"column", gap:12, alignItems:"center" }}>
                {Object.entries(seatsByRow).map(([row, rowSeats]) => (
                  <div key={row} style={{ display:"flex", alignItems:"center", gap:10 }}>
                    <span style={{ width:20, textAlign:"center", fontSize:12,
                      color:"var(--muted)", fontWeight:600 }}>{row}</span>
                    <div style={{ display:"flex", gap:8 }}>
                      {rowSeats.sort((a,b)=>a.col-b.col).map(s => {
                        const isBooked = bookedSeats.includes(s._id);
                        const isSel    = selSeat === s._id;
                        return (
                          <div key={s._id}
                            onClick={() => !isBooked && setSeat(isSel ? "" : s._id)}
                            title={s.note || s.seatNo}
                            style={{
                              width:52, height:52, borderRadius:6,
                              display:"flex", alignItems:"center",
                              justifyContent:"center", flexDirection:"column",
                              cursor: isBooked ? "not-allowed" : "pointer",
                              background: isSel ? "var(--blue)" :
                                isBooked ? "rgba(239,68,68,0.15)" : "var(--card)",
                              border:"1px solid",
                              borderColor: isSel ? "var(--blue)" :
                                isBooked ? "var(--red)" : "var(--border)",
                              transition:"all .15s",
                              transform: isSel ? "scale(1.05)" : "scale(1)",
                              boxShadow: isSel ? "0 0 12px rgba(37,99,235,0.4)" : "none",
                            }}>
                            {isSel && <span style={{ fontSize:14 }}>✓</span>}
                            <span style={{
                              fontSize:10, fontWeight:600,
                              color: isSel ? "#fff" : isBooked ? "var(--red)" : "var(--muted)",
                            }}>{s.seatNo}</span>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                ))}

                {/* Gap indicator */}
                {Object.keys(seatsByRow).length > 1 && (
                  <div style={{ color:"var(--muted)", fontSize:12, margin:"4px 0" }}>
                    — НЭВТРЭХ ХЭСЭГ —
                  </div>
                )}
              </div>

              <div style={{ display:"flex", gap:10, marginTop:24 }}>
                <button onClick={()=>setStep(1)} className="btn btn-outline" style={{ flex:1, padding:"12px 0" }}>
                  ← Буцах
                </button>
                <button onClick={()=>setStep(3)} className="btn btn-primary"
                  style={{ flex:2, padding:"12px 0" }}>
                  Баталгаажуулах →
                </button>
              </div>
            </div>
          )}

          {/* STEP 3 */}
          {step === 3 && (
            <div className="card">
              <h3 style={{ marginBottom:20, fontSize:16 }}>✅ Алхам 3: Баталгаажуулах</h3>
              <div style={{ background:"var(--surface)", borderRadius:10, padding:16, marginBottom:16 }}>
                <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:12 }}>
                  {[
                    ["Байгууллага", biz?.name],
                    ["Үйлчилгээ", selSvc?.name],
                    ["Өдөр", selDate],
                    ["Цаг", selTime],
                    ["Суудал", seats.find(s=>s._id===selSeat)?.seatNo || "Сонгоогүй"],
                    ["Нийт төлбөр", selSvc ? `₮${selSvc.price.toLocaleString()}` : "—"],
                  ].map(([k,v]) => (
                    <div key={k}>
                      <div style={{ fontSize:11, color:"var(--muted)", marginBottom:2 }}>{k}</div>
                      <div style={{ fontWeight:500, fontSize:14 }}>{v}</div>
                    </div>
                  ))}
                </div>
              </div>

              <div style={{ marginBottom:16 }}>
                <label>Тэмдэглэл (заавал биш)</label>
                <textarea value={note} onChange={e=>setNote(e.target.value)}
                  placeholder="Нэмэлт хүсэлт..." rows={3}
                  className="input" style={{ resize:"vertical" }} />
              </div>

              {msg && <div style={{ color:"var(--red)", fontSize:13, marginBottom:12 }}>{msg}</div>}

              <div style={{ fontSize:12, color:"var(--muted)", marginBottom:16 }}>
                ℹ️ Та захиалга эхлэхээс 15 минутын өмнө ирнэ үү. Цуцлах тохиолдолд 2 цагийн өмнө мэдэгдэнэ үү.
              </div>

              <div style={{ display:"flex", gap:10 }}>
                <button onClick={()=>setStep(2)} className="btn btn-outline" style={{ flex:1, padding:"12px 0" }}>
                  ← Буцах
                </button>
                <button onClick={submit} disabled={loading} className="btn btn-primary"
                  style={{ flex:2, padding:"12px 0", fontSize:15 }}>
                  {loading ? "Илгээж байна..." : "Захиалга хийх →"}
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Right summary */}
        <div className="card" style={{ height:"fit-content", position:"sticky", top:80 }}>
          <div style={{ fontWeight:700, marginBottom:16 }}>🛡 Баталгаажуулах</div>
          {biz && (
            <div style={{ display:"flex", gap:10, alignItems:"center", marginBottom:16 }}>
              <div style={{ width:44, height:44, borderRadius:8, overflow:"hidden",
                background:"var(--surface)", flexShrink:0 }}>
                {biz.images?.[0] ? <img src={biz.images[0]} alt=""
                  style={{ width:"100%", height:"100%", objectFit:"cover" }} /> : "📍"}
              </div>
              <div>
                <div style={{ fontWeight:600, fontSize:13 }}>{biz.name}</div>
                <div style={{ fontSize:11, color:"var(--muted)" }}>{biz.category}</div>
              </div>
            </div>
          )}

          {[
            ["Үйлчилгээ", selSvc?.name || "—"],
            ["Өдөр", selDate || "—"],
            ["Цаг", selTime || "—"],
            ["Суудал", seats.find(s=>s._id===selSeat)?.seatNo || "Сонгоогүй"],
          ].map(([k,v]) => (
            <div key={k} style={{ display:"flex", justifyContent:"space-between",
              padding:"8px 0", borderBottom:"1px solid var(--border)", fontSize:13 }}>
              <span style={{ color:"var(--muted)" }}>{k}:</span>
              <span style={{ fontWeight:500 }}>{v}</span>
            </div>
          ))}

          {selSvc && (
            <div style={{ marginTop:12 }}>
              <div style={{ fontSize:12, color:"var(--muted)" }}>НИЙТ ТӨЛБӨР</div>
              <div style={{ fontSize:24, fontWeight:800, color:"var(--blue)", marginTop:4 }}>
                ₮{selSvc.price.toLocaleString()}
              </div>
              <div style={{ fontSize:11, color:"var(--muted)" }}>НӨТ орсон</div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
